public class LinkedListStack {
    // Storage: Define Node structure
    private static class Node {
        int data;
        Node next;
        Node(int data) { this.data = data; }
    }

    private Node top = null; // Top of the stack reference

    // Process & Storage: Push value
    public void push(int value) {
        Node newNode = new Node(value);
        newNode.next = top;
        top = newNode;
    }

    // Process & Storage: Pop value
    public int pop() {
        if (top == null) {
            throw new IllegalStateException("Stack is empty");
        }
        int poppedValue = top.data;
        top = top.next; // Move head reference
        return poppedValue; // Output
    }

    // Output: Peek value
    public int peek() {
        if (top == null) throw new IllegalStateException("Stack is empty");
        return top.data;
    }
}

