import java.util.Stack;

public class PostfixEvaluator {
    public static int evaluate(String expr) {
        // Input: String postfix expression

        // Storage: Operand stack
        Stack<Integer> stack = new Stack<>();

        // Process: Read token-by-token
        for (int i = 0; i < expr.length(); i++) {
            char c = expr.charAt(i);
            if (c == ' ') continue;

            if (Character.isDigit(c)) {
                stack.push(c - '0'); // Storage value push
            } else {
                int val1 = stack.pop(); // Storage
                int val2 = stack.pop(); // Storage

                switch (c) {
                    case '+': stack.push(val2 + val1); break;
                    case '-': stack.push(val2 - val1); break;
                    case '*': stack.push(val2 * val1); break;
                    case '/': stack.push(val2 / val1); break;
                }
            }
        }
        // Output: final calculated value
        return stack.pop();
    }
}

import java.util.Stack;

public class InfixToPostfix {
    private static int prec(char ch) {
        switch (ch) {
            case '+': case '-': return 1;
            case '*': case '/': return 2;
            case '^': return 3;
        }
        return -1;
    }

    public static String convert(String expr) {
        // Input: Infix expression string
        StringBuilder result = new StringBuilder(); // Storage
        Stack<Character> stack = new Stack<>();     // Storage

        // Process: Operator precedence checking loops
        for (int i = 0; i < expr.length(); ++i) {
            char c = expr.charAt(i);

            if (Character.isLetterOrDigit(c)) {
                result.append(c);
            } else if (c == '(') {
                stack.push(c);
            } else if (c == ')') {
                while (!stack.isEmpty() && stack.peek() != '(') {
                    result.append(stack.pop());
                }
                stack.pop();
            } else {
                while (!stack.isEmpty() && prec(c) <= prec(stack.peek())) {
                    result.append(stack.pop());
                }
                stack.push(c);
            }
        }

        while (!stack.isEmpty()) {
            result.append(stack.pop());
        }
        // Output: Postfix string
        return result.toString();
    }
}

