import java.util.Stack;

public class StackReverser {
    public static void reverse(Stack<Integer> stack) {
        // Input: Stack to reverse in-place

        // Process: Pop elements recursively
        if (stack.isEmpty()) return;

        int temp = stack.pop(); // Storage: call stack
        reverse(stack);

        // Process: Insert popped element at bottom
        insertAtBottom(stack, temp);
    }

    private static void insertAtBottom(Stack<Integer> stack, int x) {
        if (stack.isEmpty()) {
            stack.push(x);
        } else {
            int temp = stack.pop(); // Storage
            insertAtBottom(stack, x);
            stack.push(temp);
        }
    }
}
